<svg viewBox="0 0 700 350" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Stablecoin Corporate Infrastructure — Funding &amp; Exits, 2024-2026</text>
  <g font-family="sans-serif">
    <rect x="20" y="50" width="158" height="80" rx="10" fill="#18181b" stroke="#3f3f46" stroke-width="1.3"/>
    <text x="99" y="86" fill="#38bdf8" text-anchor="middle" font-size="22" font-weight="800">$38M</text>
    <text x="99" y="108" fill="#a1a1aa" text-anchor="middle" font-size="13">Velocity Series A (Jul 14, 2026)</text>
    <rect x="186" y="50" width="158" height="80" rx="10" fill="#18181b" stroke="#3f3f46" stroke-width="1.3"/>
    <text x="265" y="86" fill="#fafafa" text-anchor="middle" font-size="22" font-weight="800">~$50M</text>
    <text x="265" y="108" fill="#a1a1aa" text-anchor="middle" font-size="13">Velocity total raised since May 2025</text>
